package server
import("encoding/json";"io";"net/http";"strconv";"strings";"time";"github.com/stockyard-dev/stockyard-assay2/internal/store")
func(s *Server)handleList(w http.ResponseWriter,r *http.Request){list,_:=s.db.List();if list==nil{list=[]store.Contract{}};writeJSON(w,200,list)}
func(s *Server)handleCreate(w http.ResponseWriter,r *http.Request){var c store.Contract;json.NewDecoder(r.Body).Decode(&c);if c.Name==""||c.URL==""{writeError(w,400,"name and url required");return};if c.Method==""{c.Method="GET"};if c.ExpectedStatus==0{c.ExpectedStatus=200};s.db.Create(&c);writeJSON(w,201,c)}
func(s *Server)handleDelete(w http.ResponseWriter,r *http.Request){id,_:=strconv.ParseInt(r.PathValue("id"),10,64);s.db.Delete(id);writeJSON(w,200,map[string]string{"status":"deleted"})}
func(s *Server)handleRun(w http.ResponseWriter,r *http.Request){id,_:=strconv.ParseInt(r.PathValue("id"),10,64);contracts,_:=s.db.List();var c store.Contract;for _,ct:=range contracts{if ct.ID==id{c=ct;break}};res:=&store.Result{ContractID:id};t0:=time.Now();req,err:=http.NewRequest(c.Method,c.URL,nil);if err!=nil{res.Error=err.Error()}else{resp,err2:=http.DefaultClient.Do(req);res.DurationMs=time.Since(t0).Milliseconds();if err2!=nil{res.Error=err2.Error()}else{defer resp.Body.Close();body,_:=io.ReadAll(resp.Body);res.ActualStatus=resp.StatusCode;statusOK:=resp.StatusCode==c.ExpectedStatus;bodyOK:=c.ExpectedBodyContains==""||strings.Contains(string(body),c.ExpectedBodyContains);res.Passed=statusOK&&bodyOK;if !res.Passed{res.Error="contract violation"}}};s.db.RecordResult(res);writeJSON(w,200,res)}
func(s *Server)handleResults(w http.ResponseWriter,r *http.Request){id,_:=strconv.ParseInt(r.PathValue("id"),10,64);list,_:=s.db.ListResults(id);if list==nil{list=[]store.Result{}};writeJSON(w,200,list)}
func(s *Server)handleOverview(w http.ResponseWriter,r *http.Request){m,_:=s.db.Stats();writeJSON(w,200,m)}
